inline void ConnectionHandle::Reset() {
    if (!conn_) return;
    auto c = std::move(conn_);
    NetworkClient* o = owner_;
    uint64_t t = token_;
    owner_ = nullptr;
    token_ = 0;
    if (o) o->Release(t, std::move(c));
    else c->Close();
}

